System.register([],function(n,e){var c,a,o,h,i,t;return{setters:[],execute:function(){a=(n,e,c,a,o,h)=>({id:n,type:"dialogue",speaker:e,speakerKey:c,text:a,sprite:o?{key:o,position:"linmo"===o?"left":"right"}:void 0,effects:h}),o=(n,e,c)=>({id:n,type:"choice",text:e,choices:c,speaker:""}),h=(n,e,c,a,o)=>({id:n,type:"quiz",text:e,quiz:c,onCorrect:a,onWrong:o,speaker:""}),i=(n,e)=>({id:n,type:"system",text:e,speaker:""}),t=(n,e,c,a)=>({id:n,type:"cg",text:e,background:c,speaker:"",cgImage:a}),n("chapter78Script",[(c=(n,e,c)=>({id:n,type:"narration",text:e,speaker:"",background:c}))("ch7-0-0","第7章：破局\n\n深夜。办公区。只有你工位上一盏台灯亮着。桌上摊开着五样东西。","office"),c("ch7-0-1","五个碎片——分别来自五个人。\n碎片A：活性中心氨基酸残基序列——林雪。\n碎片B：体外复性条件(pH6.8/37°C/氧化还原电位-280mV)——陈阳。\n碎片C：抑制剂结合位点——苏菲亚。\n碎片D：酶-底物对接自由能ΔG=-12.3 kcal/mol——小雅。\n碎片E：翻译后修饰(第127位磷酸化/第213位乙酰化)——王博士。","office"),c("ch7-0-2","父亲把QZ-酶的核心数据分成了五个碎片。每一片只有一个守护者知道。没有任何一个人能独自拼出完整配方——除了你。","office"),h("ch7-0-3","你需要在实验记录本上写下反向抑制酶的完整设计方案。",{question:"结合五个碎片的信息——活性中心含[4Fe-4S]铁硫簇(碎片A)、别构位点存在竞争性抑制剂骨架(碎片C)、ΔG_binding=-12.3 kcal/mol(碎片D)——设计反向抑制酶最关键的一步是？",options:[{label:"A",text:"直接复制QZ-酶的活性中心序列",correct:!1},{label:"B",text:"保留活性中心结构，在抑制剂骨架中加入磷酸化位点(碎片E)——使反向酶竞争性占据QZ-酶别构位点，阻断时间戳写入",correct:!0},{label:"C",text:"提高反应温度使QZ-酶变性",correct:!1},{label:"D",text:"降低pH破坏铁硫簇",correct:!1}],explanation:'反向抑制酶设计利用竞争性抑制原理：保留活性中心识别能力(碎片A)，在抑制剂骨架(碎片C)上加磷酸化修饰(碎片E)提高结合亲和力——磷酸基团形成额外盐桥，使ΔG_binding比天然底物更低(碎片D)，从而在别构位点上"挤走"天然底物。在体外复性条件(碎片B)下确保正确折叠。',knowledgeId:"reverse_enzyme_design",knowledgeTitle:"反向抑制酶——基于结构的蛋白药物设计(SBDD)"},[c("ch7-0-3c","你写下了第一行实验方案：\n\n反向抑制酶(Anti-QZ-ase)合成方案\n①基因合成：基于碎片A+C，含His127Ser突变以失活催化中心\n②体外转录-翻译：T7 RNA聚合酶+大肠杆菌S30提取物\n③体外复性：碎片B条件\n④翻译后修饰：共表达苏氨酸激酶和乙酰转移酶\n⑤活性验证：SPR测定Kd<10nM","office")],[c("ch7-0-3w","你在笔记本上划掉了错误的思路，重新开始。五个碎片缺一不可——每一个都是父亲为保护你而布下的拼图。","office")]),c("ch7-1-0","第二天早上。你把五个人召集到办公区。","office"),a("ch7-1-1","林墨","linmo","我需要你们的帮助。不是以同事的身份——是以知情者的身份。这个反向酶一旦合成——可以永久关闭QZ-酶的时间戳写入机制。轮回会结束。但代价是——张总会不惜一切阻止。你们可能会死。"),a("ch7-1-2","陈阳","chenyang","（第一个开口）我以前怕很多东西。怕试剂爆炸、怕配错浓度、怕被开除。但后来我发现——我怕的不是危险。是做了错误的选择。这次——我觉得这是对的选择。","chenyang"),a("ch7-1-3","林雪","linxue","蛋白质折叠——序列决定结构——结构决定功能。我的序列——是我父亲给我的。他那一部分——是不向错误的东西低头。算我一个。","linxue"),a("ch7-1-4","苏菲亚","sophia","（握着项链吊坠）我女儿不会希望她的妈妈是这样的人——为了救一个人而出卖另一个人。我替Emma做这个决定。","sophia"),a("ch7-1-5","小雅","xiaoya","我被制造出来——是为了辅助人类做实验。但这是我自己的选择。不是程序设定的。算我一个。","xiaoya"),a("ch7-1-6","王博士","wang","我不需要表态。我在二十五年前就做了选择——站在你父亲这边。现在只是——继续站下去。","wang"),c("ch7-2-0","B1核心实验室。五个人各自分工，像一台精密运转的机器。墙上倒计时——4:00:00。","b1_lab"),a("ch7-2-1","林雪","linxue","反向酶的基因序列合成完毕——全长873bp，编码291个氨基酸。His-tag标记——Ni-NTA纯化。密码子优化——大肠杆菌偏好。","linxue"),a("ch7-2-2","陈阳","chenyang","氧化还原电位——GSH 5mM，GSSG 0.5mM——GSH:GSSG=10:1——正确的二硫键配对环境。温度37°C——偏差超过0.5°C我就重来。","chenyang"),h("ch7-2-3","陈阳在通风橱前操作，头也不回。",{question:"二硫键在蛋白质中由哪两个氨基酸残基形成？体外复性时如何确保正确的二硫键配对？",options:[{label:"A",text:"两个半胱氨酸(Cys)的巯基(-SH)之间；通过控制GSH/GSSG比例提供适当的氧化还原环境",correct:!0},{label:"B",text:"半胱氨酸和甲硫氨酸之间",correct:!1},{label:"C",text:"两个丝氨酸之间；不需要特殊条件",correct:!1},{label:"D",text:"任何两个含硫氨基酸都可以",correct:!1}],explanation:"二硫键(-S-S-)由两个Cys残基的侧链巯基(-SH)氧化形成，是共价键。正确配对是蛋白体外复性的核心挑战——错误配对导致错误折叠和聚集。GSH/GSSG氧化还原缓冲系统提供适当的氧化还原电位：GSH:GSSG=10:1维持还原环境，使错误配对的二硫键能被还原后重新配对。",knowledgeId:"disulfide_bond_refolding",knowledgeTitle:"二硫键与体外复性——GSH/GSSG氧化还原缓冲"},[a("ch7-2-3c","陈阳","chenyang","对。二硫键——两个半胱氨酸。错一个——整个蛋白结构就错了。就像人生——有时候一步错了——后面全错。但二硫键可以还原重来——人生不行。","chenyang",{affection:{chenyang:10}})],[a("ch7-2-3w","陈阳","chenyang","Cys——半胱氨酸——侧链-SH。两个-SH氧化形成-S-S-。GSH:GSSG=10:1。记住这个比例。","chenyang")]),a("ch7-2-4","小雅","xiaoya","对接模拟完成！ΔG_binding=-14.7 kcal/mol——比天然底物的-12.3更强！反向酶会以更高亲和力结合QZ-酶别构位点——把它挤走——竞争性抑制！","xiaoya"),a("ch7-2-5","苏菲亚","sophia","质粒测序——873bp——100%正确。无一突变。基因准备好了。","sophia"),a("ch7-2-6","王博士","wang","无细胞蛋白合成系统就绪。谁来加入质粒模板？","wang"),o("ch7-2-7","王博士把移液器递向你。",[{text:"【亲自加入】深吸一口气——将质粒溶液注入反应体系",next:[c("ch7-2-7a","淡绿色的质粒溶液融入反应体系。屏幕上的实时荧光检测显示——GFP标记的反向酶开始表达。绿色荧光——逐渐增强。4小时后。林雪从Ni-NTA柱上洗脱下来一管淡绿色的液体。","b1_lab"),a("ch7-2-8","林雪","linxue","A280=0.847。蛋白浓度≈0.6mg/mL。SDS-PAGE单一条带。33kDa。CD——208nm和222nm双负峰——正确折叠。竞争性抑制实验——反向酶存在下，QZ-酶Vmax降至12%。Km不变。反向抑制酶——合成成功。","linxue"),c("ch7-2-9","林雪举起那管淡绿色的液体。五个人都围了过来。陈阳第一个笑了。小雅跳起来。苏菲亚靠在椅背上。王博士擦了擦老花镜。","b1_lab")],effects:{flag:"personally_added_plasmid"}},{text:'【交给王博士】"还是您来吧——这是最关键的一步"',next:[a("ch7-2-7b","王博士","wang","（接过移液器，手稳得不像一个54岁的人）远山——看着。你儿子的反向酶——我来加最后一滴。","wang"),c("ch7-2-8b","4小时后。反向抑制酶合成成功。","b1_lab")],effects:{affection:{wang:10}}}]),c("ch7-3-0","广播响起。张总的声音——冷静得像陈述实验方案。","b1_lab"),a("ch7-3-1","张总","zhang","恭喜。反向抑制酶合成成功。我一直在看着。做个简单的交易——把反向酶给我。所有人可以安全离开。完美结局。只要你们——把反向酶给我。","zhang"),a("ch7-3-2","林墨","linmo",'"如果你真的会销毁QZ-酶——你为什么不自已合成反向酶？你也有所有数据。"'),a("ch7-3-3","张总","zhang","（长久的沉默——然后声音里第一次出现了一种东西——不是愤怒——是疲惫）因为我不是完美适配体。反向酶需要适配体的DNA才能正确折叠。这栋楼里——只有一个人有这个突变。所以我需要你的反向酶。给你们一个小时。一个小时后——引爆全楼生化安保系统。","zhang"),c("ch7-4-0","作战会议。五个人围坐。","office"),a("ch7-4-1","林墨","linmo","分头行动。林雪——带反向酶原液去B3液氮罐。陈阳——去配浓氨水。苏菲亚——去屋顶启动卫星通讯。小雅——入侵主控拦截生物炸弹遥控信号。王博士——不要去找张总。"),a("ch7-4-2","王博士","wang","（第一次提高了声音——这个永远温和的老人——第一次用命令的语气）听我说。他欠我一条命——你父亲的。这是我和他之间的事情。你的任务——是带着反向酶活下去。","wang"),c("ch7-5-0","B3层休眠舱控制室。张总坐在金属椅子上。袖子卷起来——露出了整条手臂上的溃烂和老年斑。","b3_cryo"),a("ch7-5-1","张总","zhang","师兄。上次你叫我师兄——还是1999年。在林远山的实验室。那天我们刚从马里亚纳海沟回来。远山说——等我们把这个酶搞清楚了——诺贝尔奖就是我们三个的。","zhang"),a("ch7-5-2","王博士","wang","远山死后第二年——你去参加诺贝尔奖颁奖典礼——坐在第三排——西装革履。我当时在家看电视——想——这个人是怎么做到在一个人的葬礼和另一个人的颁奖典礼之间只隔了六个月——还能笑出来的？","wang"),a("ch7-5-3","张总","zhang","你以为我在笑？我那次从斯德哥尔摩回来——在飞机上吐了三次。不是晕机——是看到所有穿白大褂的人都想起远山的脸。每天晚上闭上眼睛——就是远山被车撞那天——他眼睛里的表情——不是恐惧——是——我早该知道的。","zhang"),c("ch7-5-4","王博士从口袋里拿出了那张泛黄的照片——林远山和年轻的张启明。三十岁。浙大生化楼。举着刚纯化出的第一管QZ-酶。笑得像两个孩子。","b3_cryo"),a("ch7-5-5","王博士","wang","远山临走前——让我带句话给你。他说——我不怪你。但请你——别再跑了。","wang"),c("ch7-5-6","张总的手悬在照片上方——离照片只有一厘米。停了很久。然后收回了手。","b3_cryo"),a("ch7-5-7","张总","zhang","生化安保系统的总控密钥——在主控台下面——红色按钮。输入——远山的生日。1971年3月15日。把反向酶注入环境控制系统——通过通风管道扩散——和空气中的QZ-酶结合——失活。这是我唯一能做的事情了。就当——付了二十五年的房租。","zhang"),c("ch7-6-0","全楼警报停止。陈阳的氨水中和了空气中的QZ-酶。苏菲亚的卫星信号发出。小雅拦截了引爆信号。林雪把反向酶存入了液氮罐。张总从椅子上滑到地板上。Werner综合征终末期——多器官衰竭。","b3_cryo"),a("ch7-6-1","张总","zhang","告诉林墨——他父亲的实验记录本——第37页——有一个夹层——里面有QZ-酶的完整结构——包括在线粒体呼吸链中替代缺陷复合体的机制——远山本来想发表的——被我一直锁在保险箱里。现在——交给他儿子。","zhang"),c("ch7-6-2",'王博士从抽屉里找到了那个信封——远山在张启明结婚那天写给他的：\n\n"启明：不管发生什么——我相信你心里那个好人还在。你的师兄，远山"',"b3_cryo"),a("ch7-6-3","张总","zhang","（二十五年来第一次——哭了）远山。对不起。那个好人一直在。只是被我锁在了一个——太深的地方。","zhang"),c("ch7-6-4","生命体征监测仪变成了一条直线。张启明靠在休眠舱旁。手里捏着远山的信和三个人的合影。休眠舱绿色的光打在他脸上——让他看起来像在1999年的阳光下——笑着举着第一管QZ-酶。","b3_cryo"),c("ch8-0-0","第8章：终局\n\nB1核心实验室。你握着那管淡绿色的反向酶。五个人都在。","b1_lab"),a("ch8-0-1","林雪","linxue","反向酶只能通过静脉注射。直接进入血液——经过心脏——泵入全身——与线粒体中的QZ-酶结合。但有一个风险——反向酶和QZ-酶的结合会引发免疫反应。约有22%的概率——你会死。永久性的。不能再轮回。","linxue"),o("ch8-0-2","⭐ 最终抉择 ⭐\n\n注射器在你手中。针尖在日光灯下反射出一点银光。",[{text:"【自己注射】将反向酶注入颈静脉——自己掌控",next:[t("ch8-inject-cg","针尖刺入颈静脉。淡绿色的液体缓缓推入。一分钟——体温升高。一分三十秒——心率飙到180。两分钟——视野模糊。两分四十秒——心率回落。两分五十八秒——你睁开眼。五个人都在哭。轮回——结束了。","b1_lab","/images/cg/cg_reverse_enzyme_injection.png"),c("ch8-0-2a","针尖刺入颈静脉。淡绿色的液体缓缓推入。一分钟——体温升高——免疫反应启动。一分三十秒——心率飙到180。两分钟——视野模糊——和第一次死亡时一模一样。两分四十秒——心率回落——视野清晰。两分五十八秒——你睁开眼。Five people all crying.","b1_lab"),c("ch8-0-2a2","三十分钟后。质谱结果——QZ-酶66kDa+反向酶33kDa=异源二聚体99kDa。时间戳写入活性——0。完全抑制。轮回——结束。","b1_lab")],effects:{flag:"self_injected",san:-5}},{text:"【让林雪注射】她操作最精准",next:[a("ch8-0-2b","林雪","linxue","（接过注射器——手——竟然在抖——她第一次手握移液器以外的东西会抖）别动。","linxue"),c("ch8-0-2b2","她那以微升级精度闻名的手——在刺入你颈静脉时——稳得像在做晶体衍射。反向酶推入。轮回结束。","b1_lab")],effects:{affection:{linxue:20},flag:"linxue_injected"}}]),c("ch8-1-0","六个月后。","rooftop_day"),c("ch8-1-1",'林雪在MIT发表了一篇关于QZ-酶结构-功能关系的Nature论文。致谢最后一段："感谢林墨——那个在我以为所有人都是NPC的实验室里，第一个证明给我看人会为别人站出来的人。"',"rooftop_day"),c("ch8-1-2",'陈阳的有机试剂店"产率>99%"开张了。傻瓜手册被整理成《生化实验安全手册》正式出版——第一笔版税捐给了罕见病基金会。',"office"),c("ch8-1-3",'苏菲亚的Emma实现了临床治愈。QZ-酶的工程化变体补偿了ATP6突变的缺陷。苏菲亚在盖亚协议内部推动改革——从"扼杀危险科技"变成"引导危险科技走向治疗"。',"office"),c("ch8-1-4",'小雅被邀请加入国际AI伦理委员会——"因为我是唯一一个既是人类又不是人类的委员。"她提交的提案标题："关于AI的人权——从分子层面定义活着的权利。"附带128407行情感日志。',"office"),c("ch8-1-5",'王博士退休了。他的代谢通路图被印成大幅海报，挂在全世界几千个生化教室里。海报右下角："献给林远山——我的师兄，我的朋友。你的通路，还在跑。"',"office"),c("ch8-1-6","张启明的骨灰被撒在马里亚纳海沟——最初发现QZ-酶的热液喷口。摄氏350°C的海底火山口。没有任何标记。只有生命最初的形式在黑暗中——继续活着。","dark"),c("ch8-2-0","咖啡馆。窗外银杏叶金黄。","breakroom"),c("ch8-2-1","你喝着咖啡。一切都很平静。然后——你低头看到了杯底。咖啡喝干后，杯底的纹路露出来。那不是随机纹理——那是一个标志。被锁链缠绕的火焰。塔耳塔洛斯。","breakroom"),c("ch8-2-2","翻转杯子——杯底贴着一张小得几乎看不见的二维码。掏出手机扫描。屏幕上出现一行文字：","breakroom"),t("ch8-final",'"第114514次轮回——数据采集完毕。"\n"感谢您的参与。"\n"本次实验的观察对象已成功通过所有测试阶段。"\n"反向抑制酶——已验证有效。"\n"实验目的达成：确认人类个体在知晓轮回机制后，会自主选择终止轮回而非滥用轮回。"\n"结论：时间回溯技术对人类文明的风险可控。"\n"下一阶段实验：向有限的候选者开放时间回溯能力——作为终末期患者的最后选择。"\n"实验代号：PROJECT PROMETHEUS II"\n"实验总监签名：——"\n\n签名的位置——是一个DNA双螺旋的Logo。\n下面一行极小的小字：\n"没有人在监视你。我们在守护你。"',"breakroom","/images/cg/cg_coffee_cup_reveal.png"),t("ch8-end","夕阳照在杯底——锁链缠绕的火焰。但这一次——火焰中心——那个被锁链束缚的东西——不再是痛苦。\n\n而是一颗小小的——正在发芽的种子。\n\n时间是一条单行道。过去无法改变。\n但未来——取决于你的下一个选择。\n不是被设计好的选择——是你自己的。\n\n——林远山，最后的实验记录，1999年12月24日","rooftop_day","/images/cg/cg_all_six_rooftop.png"),i("ch8-final-sys","▎终章完结\n\n真结局达成：永恒的轮回（True End）\n成就解锁：蛋白复合体 / 安芬森的最后一个学生 / 线粒体的新生\n\n感谢你的选择。\n\n——林远山 / 林墨 / 6位守护者 / 1位反派\n——每一个曾在这栋楼里活过、爱过、死去过的人\n\n再见。或者——在新一轮实验中见。"),t("ch8-bonus",'彩蛋结局：大肠杆菌的复仇\n\n在某个平行宇宙中——\n一只携带了QZ-酶基因的E.coli获得了意识。\n它在琼脂平板上用鞭毛画了一个笑脸——\n然后开始了自己的轮回实验。\n\n"第114514次分裂——数据采集完毕。"\n"人类的生化考试——全部通过。"\n\n——祝你实验顺利 🧫',"rooftop_day","/images/cg/cg_e_coli_ending.png")])}}});